import { useDropzone } from 'react-dropzone';

export function DocumentsPane({ matterId }: Props) {
  const { getRootProps, getInputProps } = useDropzone({ accept: 'image/*,application/pdf' });
  return (
    <div {...getRootProps()}>
      <input type="file" {...getInputProps()} multiple />
      <button>Upload Document</button>
    </div>
  );
}

import multer from 'multer';
import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';

const upload = multer({ storage: multer.memoryStorage() });
const s3 = new S3Client({ region: 'us-east-1' });

router.post('/upload', upload.single('file'), async (req, res) => {
  const params = { Bucket: 'docs', Key: req.file.originalname, Body: req.file.buffer };
  await s3.send(new PutObjectCommand(params));
  res.json({ ok: true });
});

